    93→  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
    94→}
    95→
    96→
    97→interface StoredData {
    98→  workspace: Workspace
    99→  windowBounds?: WindowBounds
   100→  settings?: Settings
   101→}
   102→
   103→export class SessionStore {
   104→  private configPath: string
   105→  private backupPath: string
   106→  private data: StoredData
   107→
   108→  constructor() {
   109→    const configDir = join(app.getPath('userData'), 'config')
   110→    if (!existsSync(configDir)) {
   111→      mkdirSync(configDir, { recursive: true })
   112→    }
   113→    this.configPath = join(configDir, 'workspace.json')
   114→    this.backupPath = join(configDir, 'workspace.json.backup')
   115→    this.data = this.load()
   116→  }
   117→
   118→  private loadFile(path: string): StoredData | null {
   119→    try {
   120→      if (!existsSync(path)) return null
   121→      const stat = statSync(path)
   122→      if (stat.size === 0) return null
   123→      const content = readFileSync(path, 'utf-8')
   124→      const data = JSON.parse(content)
   125→      if (!data?.workspace) return null
   126→      return data
   127→    } catch (e) {
   128→      console.error(`[SessionStore] Failed to load ${path}:`, e)
   129→      return null
   130→    }
   131→  }
   132→
   133→  private load(): StoredData {
   134→    // Try main file first
   135→    const main = this.loadFile(this.configPath)
   136→    if (main && (main.workspace.projects?.length || 0) > 0) {
   137→      return main
   138→    }
   139→
   140→    // Main file is empty/corrupt/missing — try backup
   141→    const backup = this.loadFile(this.backupPath)
   142→    if (backup && (backup.workspace.projects?.length || 0) > 0) {
   143→      console.log('[SessionStore] Main config empty/corrupt, restored from backup (' +
   144→        backup.workspace.projects.length + ' projects)')
   145→      // Restore backup as main file atomically (temp + rename)
   146→      try {
   147→        const tmpPath = this.configPath + '.tmp'
   148→        writeFileSync(tmpPath, JSON.stringify(backup, null, 2))
   149→        renameSync(tmpPath, this.configPath)
   150→      } catch (e) {
   151→        console.error('[SessionStore] Failed to restore backup to main:', e)
   152→      }
   153→      return backup
   154→    }
   155→
   156→    // If main loaded but had 0 projects (valid empty state), use it
   157→    if (main) return main
   158→
   159→    return {
   160→      workspace: {
   161→        projects: [],
   162→        openTabs: [],
   163→        activeTabId: null
   164→      }
   165→    }
   166→  }
   167→
   168→  private save(): void {
   169→    try {
   170→      const json = JSON.stringify(this.data, null, 2)
   171→
   172→      // Validate we can parse what we're about to write
   173→      JSON.parse(json)
   174→
   175→      // Back up existing file before overwriting (if it has content)
   176→      if (existsSync(this.configPath)) {
   177→        try {
   178→          const stat = statSync(this.configPath)
   179→          if (stat.size > 0) {
   180→            // Only update backup if existing file is valid and has projects
   181→            const existing = this.loadFile(this.configPath)
   182→            if (existing && (existing.workspace.projects?.length || 0) > 0) {
   183→              // Atomic backup: write to temp file, then rename
   184→              const tmpBackup = this.backupPath + '.tmp'
   185→              writeFileSync(tmpBackup, readFileSync(this.configPath))
   186→              renameSync(tmpBackup, this.backupPath)
   187→            }
   188→          }
   189→        } catch (e) {
   190→          console.error('[SessionStore] Failed to update backup:', e)
   191→        }
   192→      }
   193→
   194→      // Atomic write: write to temp file, then rename
   195→      const tmpPath = this.configPath + '.tmp'
   196→      writeFileSync(tmpPath, json)
   197→
   198→      try {
   199→        // Verify the temp file was written completely
   200→        const written = readFileSync(tmpPath, 'utf-8')
   201→        JSON.parse(written) // throws if truncated/corrupt
   202→        renameSync(tmpPath, this.configPath)
   203→      } catch (verifyErr) {
   204→        // Clean up temp file on verification or rename failure
   205→        try { unlinkSync(tmpPath) } catch { /* ignore cleanup errors */ }
   206→        throw verifyErr
   207→      }
   208→    } catch (e) {
   209→      console.error('[SessionStore] Failed to save workspace:', e)
   210→    }
   211→  }
   212→
   213→  getWorkspace(): Workspace {
   214→    return this.data.workspace
   215→  }
   216→
   217→  // Reload workspace from disk (useful when file was modified externally)
   218→  reloadFromDisk(): void {
   219→    console.log('[SessionStore] Reloading workspace from disk')
   220→    this.data = this.load()
   221→    console.log('[SessionStore] Reloaded, projects:', this.data.workspace?.projects?.length || 0)
   222→  }
   223→
   224→  saveWorkspace(workspace: Workspace): void {
   225→    // Protect against overwriting populated workspace with empty one
   226→    const incomingProjects = workspace?.projects?.length || 0
   227→    const currentProjects = this.data.workspace?.projects?.length || 0
   228→    if (incomingProjects === 0 && currentProjects > 0) {
   229→      console.log('[SessionStore] Rejected empty workspace save - current has', currentProjects, 'projects')
   230→      return
   231→    }
   232→    this.data.workspace = workspace
   233→    this.save()
   234→    syncMetaProjects(workspace)
   235→  }
   236→
   237→  getWindowBounds(): WindowBounds | undefined {
   238→    return this.data.windowBounds
   239→  }
   240→
   241→  saveWindowBounds(bounds: WindowBounds): void {
   242→    this.data.windowBounds = bounds
   243→    this.save()
   244→  }
   245→
   246→  getSettings(): Settings {
   247→    return this.data.settings ?? { defaultProjectDir: '', theme: 'default', backend: 'default' }
   248→  }
   249→
   250→  saveSettings(settings: Settings): void {
   251→    this.data.settings = settings
   252→    this.save()
   253→  }
   254→}
