    25→
    26→      // Only allow localhost
    27→      const remote = req.socket.remoteAddress
    28→      if (remote !== '127.0.0.1' && remote !== '::1' && remote !== '::ffff:127.0.0.1') {
    29→        res.writeHead(403)
    30→        res.end(JSON.stringify({ error: 'Forbidden' }))
    31→        return
    32→      }
