    34→      const url = new URL(req.url || '/', `http://localhost:${this.activePort}`)
    35→      const path = url.pathname
    36→
    37→      // Match: /sessions/:id/output or /sessions/:id/input
    38→      const sessionMatch = path.match(/^\/sessions\/([^/]+)\/(output|input)$/)
    39→
    40→      if (req.method === 'GET' && path === '/sessions') {
    41→        this.handleListSessions(res)
    42→      } else if (req.method === 'GET' && sessionMatch?.[2] === 'output') {
    43→        const maxLines = parseInt(url.searchParams.get('lines') || '50', 10)
    44→        this.handleReadOutput(sessionMatch[1], maxLines, res)
    45→      } else if (req.method === 'POST' && sessionMatch?.[2] === 'input') {
    46→        this.handleSendInput(sessionMatch[1], req, res)
