    54→  }
    55→
    56→  private tryListen(port: number): void {
    57→    const retryCount = port - ORCHESTRATOR_PORT
    58→    if (retryCount >= MAX_PORT_RETRIES) {
    59→      console.error(`[Orchestrator] Failed to bind after ${MAX_PORT_RETRIES} attempts (ports ${ORCHESTRATOR_PORT}-${port - 1})`)
    60→      this.server?.close()
    61→      this.server = null
    62→      return
    63→    }
    64→
