   140→        res.end(JSON.stringify({ success: true, message: `Input sent to session ${id}` }))
   141→      } catch {
   142→        res.writeHead(400)
   143→        res.end(JSON.stringify({ error: 'Invalid JSON' }))
   144→      }
   145→    })
   146→  }
   147→}
