225→  // Kspec uses WebSocket for live updates instead of file watching
226→  private ws: WebSocket | null = null
227→  private wsCallbacks: Set<(data: { cwd: string }) => void> = new Set()
228→  private watchedCwd: string | null = null
229→  private reconnectTimer: ReturnType<typeof setTimeout> | null = null
230→  private reconnectDelay = 1000
231→  private watching = false
