/**
 * PTY Routes - /api/pty/* endpoints
 */

import { Express, Request, Response } from 'express'
import { WebSocket } from 'ws'
import { validateProjectPath } from '../../mobile-security'
import { log } from '../utils'
import { LocalPty } from '../types'

export function setupPtyRoutes(
  app: Express,
  getPtyManager: () => any,
  getLocalPtys: () => Map<string, LocalPty>,
  getPtyStreams: () => Map<string, Set<WebSocket>>,
  getPtyDataBuffer: () => Map<string, string[]>,
  broadcastPtyData: (ptyId: string, data: string) => void,
  broadcastPtyExit: (ptyId: string, code: number) => void
): void {
  // Spawn a new PTY
  app.post('/api/pty/spawn', async (req: Request, res: Response) => {
    try {
      const { projectPath, sessionId, model, backend } = req.body

      if (!projectPath || typeof projectPath !== 'string') {
        return res.status(400).json({ error: 'projectPath is required' })
      }

      const pathValidation = validateProjectPath(projectPath)
      if (!pathValidation.valid) {
        return res.status(400).json({ error: pathValidation.error })
      }
      const safeProjectPath = pathValidation.normalizedPath!

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      log('PTY spawn request', { projectPath: safeProjectPath, sessionId, model, backend })

      const ptyId = ptyManager.spawn(
        safeProjectPath,
        sessionId,
        undefined, // autoAcceptTools
        undefined, // permissionMode
        model,
        backend
      )

      // Track this PTY for cleanup
      const localPty: LocalPty = {
        ptyId,
        projectPath: safeProjectPath,
        dataCallbacks: new Set(),
        exitCallbacks: new Set()
      }
      getLocalPtys().set(ptyId, localPty)

      // Set up data forwarding to WebSocket streams
      ptyManager.onData(ptyId, (data: string) => {
        broadcastPtyData(ptyId, data)
      })

      // Set up exit handler
      ptyManager.onExit(ptyId, (code: number) => {
        log('PTY exited', { ptyId, code })
        broadcastPtyExit(ptyId, code)
        getLocalPtys().delete(ptyId)
        getPtyStreams().delete(ptyId)
        getPtyDataBuffer().delete(ptyId)
      })

      log('PTY spawned', { ptyId, projectPath })
      res.json({ ptyId })
    } catch (error) {
      log('PTY spawn error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })

  // Write data to PTY
  app.post('/api/pty/:id/write', (req: Request, res: Response) => {
    try {
      const { id } = req.params
      const { data } = req.body

      if (!data || typeof data !== 'string') {
        return res.status(400).json({ error: 'data is required and must be a string' })
      }

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      if (!ptyManager.getProcess(id)) {
        return res.status(404).json({ error: 'PTY not found' })
      }

      ptyManager.write(id, data)
      log('PTY write', { ptyId: id, dataLength: data.length })
      res.json({ success: true })
    } catch (error) {
      log('PTY write error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })

  // Resize PTY
  app.post('/api/pty/:id/resize', (req: Request, res: Response) => {
    try {
      const { id } = req.params
      const { cols, rows } = req.body

      if (typeof cols !== 'number' || typeof rows !== 'number') {
        return res.status(400).json({ error: 'cols and rows are required and must be numbers' })
      }

      if (cols < 1 || rows < 1 || cols > 500 || rows > 500) {
        return res.status(400).json({ error: 'cols and rows must be between 1 and 500' })
      }

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      if (!ptyManager.getProcess(id)) {
        return res.status(404).json({ error: 'PTY not found' })
      }

      ptyManager.resize(id, cols, rows)
      log('PTY resize', { ptyId: id, cols, rows })
      res.json({ success: true })
    } catch (error) {
      log('PTY resize error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })

  // Kill PTY
  app.delete('/api/pty/:id', (req: Request, res: Response) => {
    try {
      const { id } = req.params

      const ptyManager = getPtyManager()
      if (!ptyManager) {
        return res.status(500).json({ error: 'PTY manager not available' })
      }

      if (!ptyManager.getProcess(id)) {
        return res.status(404).json({ error: 'PTY not found' })
      }

      ptyManager.kill(id)
      getLocalPtys().delete(id)

      // Close any WebSocket streams for this PTY
      const streams = getPtyStreams().get(id)
      if (streams) {
        streams.forEach(ws => {
          if (ws.readyState === WebSocket.OPEN) {
            ws.close(1000, 'PTY killed')
          }
        })
        getPtyStreams().delete(id)
      }

      log('PTY killed', { ptyId: id })
      res.json({ success: true })
    } catch (error) {
      log('PTY kill error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })
}

/**
 * Workspace Routes - /api/workspace, /api/settings, /api/sessions, /api/project endpoints
 */

import { Express, Request, Response } from 'express'
import { basename } from 'path'
import { validateProjectPath } from '../../mobile-security'
import { discoverSessions } from '../../session-discovery'
import { log } from '../utils'

export function setupWorkspaceRoutes(
  app: Express,
  getSessionStore: () => any
): void {
  // Reload workspace from disk
  app.post('/api/workspace/reload', async (_req: Request, res: Response) => {
    try {
      const sessionStore = getSessionStore()
      if (!sessionStore) {
        return res.status(500).json({ error: 'Session store not available' })
      }
      sessionStore.reloadFromDisk()
      const workspace = sessionStore.getWorkspace()
      res.json({ success: true, projectCount: workspace.projects?.length || 0 })
    } catch (error) {
      res.status(500).json({ error: String(error) })
    }
  })

  app.get('/api/workspace', async (_req: Request, res: Response) => {
    try {
      const sessionStore = getSessionStore()
      if (!sessionStore) {
        return res.status(500).json({ error: 'Session store not available' })
      }
      const workspace = sessionStore.getWorkspace()
      res.json(workspace)
    } catch (error) {
      res.status(500).json({ error: String(error) })
    }
  })

  app.put('/api/workspace', async (req: Request, res: Response) => {
    try {
      const sessionStore = getSessionStore()
      if (!sessionStore) {
        return res.status(500).json({ error: 'Session store not available' })
      }
      // Protect against overwriting populated workspace with empty one
      const incoming = req.body
      const incomingProjects = incoming?.projects?.length || 0
      if (incomingProjects === 0) {
        const current = sessionStore.getWorkspace()
        const currentProjects = current?.projects?.length || 0
        if (currentProjects > 0) {
          log('Rejected empty workspace save - current has projects', { currentProjects })
          return res.status(400).json({ error: 'Cannot overwrite populated workspace with empty one' })
        }
      }
      sessionStore.saveWorkspace(req.body)
      res.json({ success: true })
    } catch (error) {
      res.status(500).json({ error: String(error) })
    }
  })

  app.post('/api/workspace', async (req: Request, res: Response) => {
    try {
      const sessionStore = getSessionStore()
      if (!sessionStore) {
        return res.status(500).json({ error: 'Session store not available' })
      }
      // POST expects { workspace: {...} } wrapper format
      const incoming = req.body
      const workspace = incoming?.workspace
      if (!workspace) {
        return res.status(400).json({ error: 'Missing workspace field in request body' })
      }
      // Protect against overwriting populated workspace with empty one
      const incomingProjects = workspace?.projects?.length || 0
      if (incomingProjects === 0) {
        const current = sessionStore.getWorkspace()
        const currentProjects = current?.projects?.length || 0
        if (currentProjects > 0) {
          log('Rejected empty workspace save - current has projects', { currentProjects })
          return res.status(400).json({ error: 'Cannot overwrite populated workspace with empty one' })
        }
      }
      sessionStore.saveWorkspace(workspace)
      res.json({ success: true })
    } catch (error) {
      res.status(500).json({ error: String(error) })
    }
  })

  // Settings routes
  app.get('/api/settings', async (_req: Request, res: Response) => {
    try {
      const sessionStore = getSessionStore()
      if (!sessionStore) {
        return res.status(500).json({ error: 'Session store not available' })
      }
      const settings = sessionStore.getSettings()
      res.json(settings)
    } catch (error) {
      res.status(500).json({ error: String(error) })
    }
  })

  app.put('/api/settings', async (req: Request, res: Response) => {
    try {
      const sessionStore = getSessionStore()
      if (!sessionStore) {
        return res.status(500).json({ error: 'Session store not available' })
      }
      sessionStore.saveSettings(req.body)
      res.json({ success: true })
    } catch (error) {
      res.status(500).json({ error: String(error) })
    }
  })

  app.post('/api/settings', async (req: Request, res: Response) => {
    try {
      const sessionStore = getSessionStore()
      if (!sessionStore) {
        return res.status(500).json({ error: 'Session store not available' })
      }
      sessionStore.saveSettings(req.body)
      res.json({ success: true })
    } catch (error) {
      res.status(500).json({ error: String(error) })
    }
  })

  // Sessions discovery
  app.get('/api/sessions', async (req: Request, res: Response) => {
    try {
      const projectPath = req.query.path as string
      const backend = (req.query.backend as 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider') || 'claude'
      if (!projectPath) {
        return res.status(400).json({ error: 'Missing path' })
      }

      const pathValidation = validateProjectPath(projectPath)
      if (!pathValidation.valid) {
        return res.status(400).json({ error: pathValidation.error })
      }
      const safeProjectPath = pathValidation.normalizedPath!

      const sessions = await discoverSessions(safeProjectPath, backend)
      res.json({ sessions })
    } catch (error: any) {
      log('Sessions error', { error: String(error) })
      res.status(500).json({ error: error.message || String(error) })
    }
  })

  // Project add
  app.post('/api/project/add', async (req: Request, res: Response) => {
    try {
      const { path: projectPath } = req.body

      if (!projectPath || typeof projectPath !== 'string') {
        return res.status(400).json({ error: 'path is required and must be a string' })
      }

      const pathValidation = validateProjectPath(projectPath)
      if (!pathValidation.valid) {
        return res.status(400).json({ error: pathValidation.error })
      }
      const safeProjectPath = pathValidation.normalizedPath!

      const name = basename(safeProjectPath)

      log('Project add', { path: safeProjectPath, name })
      res.json({ path: safeProjectPath, name })
    } catch (error) {
      log('Project add error', { error: String(error) })
      res.status(500).json({ error: String(error) })
    }
  })
}

